import React from 'react';
import {Form,Button,Container} from 'react-bootstrap'
import logo from './logo.png'
import {setUserData} from './oprate/localstorage'
function VideoConf() {
  return(
    <Container>
        <Form onSubmit={submit}>
            <br/>
            <center>
                <img src={logo}></img>
                <br/>
                <h3>dStudio video conference Beta version</h3>
            </center>
            
            <br/>
            <br/>
            <br/>
            <Form.Group controlId="formBasicEmail">
                <center><Form.Label>RoomId</Form.Label></center>
                    <Form.Control type="text" placeholder="Enter meeting Id" name="roomId" style={{textAlign:'center'}}/>
                    <br/>
                <center><Form.Label>Your Name</Form.Label></center>
                    <Form.Control type="text" placeholder="Enter your Name" name="name" style={{textAlign:'center'}}/>
                </Form.Group>
                <center><Button variant="primary" type="submit">Go to Meeting</Button></center>
        </Form>
    </Container>

  );
}
const  submit = async(e) =>{
    e.preventDefault()
    let data=e.target
    const roomId=data.elements.roomId.value
    const name=data.elements.name.value
    await setUserData(name)
    const base_url="https://devidjoshua.github.io/?roomId="+roomId
    window.location=base_url
}

export default VideoConf;
